class Solution {
    int sum = 0;
    void revInorder(TreeNode* n) {
        if (!n) return;
        revInorder(n->right);
        sum += n->val;
        n->val = sum;
        revInorder(n->left);
    }
public:
    TreeNode* convertBST(TreeNode* root) {
        revInorder(root);
        return root;
    }
};
